import { useLocation, useNavigate } from "react-router-dom";
import "./styles/Dashboard.css";

function StudentDashboard() {
  const location = useLocation();
  const navigate = useNavigate();

  const name = location.state?.name || "Student";

  return (
  <div className="user-dashboard">
    <h1 className="user-title">Welcome to Your Library</h1>

    <div className="user-cards">
      <div className="user-card">📚 Browse Books</div>
      <div className="user-card">📖 My Borrowed Books</div>
      <div className="user-card">↩️ Return Book</div>
      <div className="user-card">👤 Profile</div>
    </div>
  </div>
);

}

export default StudentDashboard;
